import math

def solve(nums: list[int]) -> int:
    n = len(nums)
    max_index = n - 1
    sieve = [True] * (max_index + 1)
    sieve[0] = sieve[1] = False
    for i in range(2, int(math.sqrt(max_index)) + 1):
        if sieve[i]:
            for j in range(i * i, max_index + 1, i):
                sieve[j] = False
    sumA = 0
    sumB = 0
    for i in range(n):
        if sieve[i]:
            sumA += nums[i]
        else:
            sumB += nums[i]
    return abs(sumA - sumB)
